import React, { useState, useEffect } from 'react'
import { supabase } from '../../lib/supabaseClient'

export const FindPlayers: React.FC = () => {
  const [searchSport, setSearchSport] = useState('')
  const [searchLocation, setSearchLocation] = useState('')
  const [players, setPlayers] = useState<any[]>([])
  const [loading, setLoading] = useState(false)
  const [currentUser, setCurrentUser] = useState<any>(null)

  useEffect(() => {
    supabase.auth.getUser().then(({ data }) => setCurrentUser(data.user))
    loadPlayers()
  }, [])

  const loadPlayers = async () => {
    setLoading(true)
    let query = supabase
      .from('users')
      .select('*')
      .neq('id', currentUser?.id || '')
      .eq('status', 'active')

    if (searchSport) {
      query = query.ilike('sport_interests', `%${searchSport}%`)
    }
    if (searchLocation) {
      query = query.ilike('location', `%${searchLocation}%`)
    }

    const { data, error } = await query
    if (!error) setPlayers(data || [])
    setLoading(false)
  }

  const handleSearch = (e: React.FormEvent) => {
    e.preventDefault()
    loadPlayers()
  }

  return (
    <div style={{
      minHeight: '100vh',
      background: '#0a0a0a',
      color: 'white',
      padding: '24px'
    }}>
      <div style={{ maxWidth: '900px', margin: '0 auto' }}>
        <h1 style={{ color: '#FFD700', fontSize: '28px', marginBottom: '8px' }}>👥 Find Players</h1>
        <p style={{ color: '#666', marginBottom: '24px' }}>Search for players by sport or location</p>

        {/* Search Form */}
        <form onSubmit={handleSearch} style={{
          background: '#0d0d0d',
          border: '1px solid #c8a20020',
          borderRadius: '12px',
          padding: '20px',
          marginBottom: '24px',
          display: 'flex',
          gap: '12px',
          flexWrap: 'wrap'
        }}>
          <input
            type="text"
            value={searchSport}
            onChange={(e) => setSearchSport(e.target.value)}
            placeholder="Search by sport..."
            style={{
              flex: 1,
              minWidth: '150px',
              padding: '12px',
              background: '#1a1a1a',
              border: '1px solid #333',
              borderRadius: '8px',
              color: 'white',
              fontSize: '14px'
            }}
          />
          <input
            type="text"
            value={searchLocation}
            onChange={(e) => setSearchLocation(e.target.value)}
            placeholder="Search by location..."
            style={{
              flex: 1,
              minWidth: '150px',
              padding: '12px',
              background: '#1a1a1a',
              border: '1px solid #333',
              borderRadius: '8px',
              color: 'white',
              fontSize: '14px'
            }}
          />
          <button
            type="submit"
            style={{
              padding: '12px 24px',
              background: 'linear-gradient(to right, #c8a200, #FFD700)',
              border: 'none',
              borderRadius: '8px',
              color: '#0a0a0a',
              fontWeight: 'bold',
              cursor: 'pointer'
            }}
          >
            🔍 Search
          </button>
          <button
            type="button"
            onClick={() => {
              setSearchSport('')
              setSearchLocation('')
              loadPlayers()
            }}
            style={{
              padding: '12px 24px',
              background: 'transparent',
              border: '1px solid #333',
              borderRadius: '8px',
              color: '#666',
              cursor: 'pointer'
            }}
          >
            Clear
          </button>
        </form>

        {/* Results */}
        {loading ? (
          <div style={{ textAlign: 'center', color: '#666', padding: '40px' }}>Loading...</div>
        ) : players.length === 0 ? (
          <div style={{
            background: '#0d0d0d',
            border: '1px solid #c8a20020',
            borderRadius: '12px',
            padding: '40px',
            textAlign: 'center',
            color: '#666'
          }}>
            <div style={{ fontSize: '48px', marginBottom: '16px' }}>🔍</div>
            <h3 style={{ color: '#888' }}>No players found</h3>
            <p>Try adjusting your search filters</p>
          </div>
        ) : (
          <div style={{ display: 'grid', gap: '12px' }}>
            {players.map((player) => (
              <div key={player.id} style={{
                background: '#0d0d0d',
                border: '1px solid #c8a20020',
                borderRadius: '12px',
                padding: '16px 20px',
                display: 'flex',
                justifyContent: 'space-between',
                alignItems: 'center',
                flexWrap: 'wrap'
              }}>
                <div>
                  <h3 style={{ fontWeight: 'bold', fontSize: '16px' }}>{player.full_name}</h3>
                  <div style={{ display: 'flex', gap: '16px', marginTop: '4px', flexWrap: 'wrap' }}>
                    {player.sport_interests && (
                      <span style={{ color: '#c8a200', fontSize: '13px' }}>
                        ⚽ {player.sport_interests}
                      </span>
                    )}
                    {player.location && (
                      <span style={{ color: '#666', fontSize: '13px' }}>
                        📍 {player.location}
                      </span>
                    )}
                    <span style={{
                      background: player.role === 'Coach' ? '#1a3a5c' : '#1a3a1a',
                      color: player.role === 'Coach' ? '#7fc8f8' : '#52c07a',
                      padding: '2px 10px',
                      borderRadius: '20px',
                      fontSize: '11px'
                    }}>
                      {player.role || 'Player'}
                    </span>
                  </div>
                </div>
                <button
                  onClick={() => alert(`💬 Message ${player.full_name} coming soon!\n(UC5 - Messages)`)}
                  style={{
                    padding: '8px 16px',
                    background: 'transparent',
                    border: '1px solid #c8a200',
                    borderRadius: '8px',
                    color: '#c8a200',
                    cursor: 'pointer',
                    fontWeight: 'bold',
                    fontSize: '13px'
                  }}
                >
                  💬 Message
                </button>
              </div>
            ))}
          </div>
        )}
      </div>
    </div>
  )
}
